import time
import requests
from dataclasses import dataclass
from datetime import datetime, UTC
from typing import Optional

@dataclass
class ProbeResult:
    vendor_id: str
    timestamp: datetime
    latency_ms: float
    http_status: int
    success: bool
    error: Optional[str] = None

class VendorProbe:
    def __init__(self, vendor_id: str, health_url: str, api_key: str,
                 timeout_s: float = 5.0):
        self.vendor_id = vendor_id
        self.health_url = health_url
        self.headers = {"Authorization": f"Bearer {api_key}"}
        self.timeout_s = timeout_s

    def probe(self) -> ProbeResult:
        start = time.monotonic()
        try:
            resp = requests.get(self.health_url, headers=self.headers,
                                timeout=self.timeout_s)
            latency_ms = (time.monotonic() - start) * 1000
            return ProbeResult(
                vendor_id=self.vendor_id,
                timestamp=datetime.now(UTC),
                latency_ms=latency_ms,
                http_status=resp.status_code,
                success=resp.status_code == 200,
            )
        except requests.exceptions.Timeout:
            return ProbeResult(
                vendor_id=self.vendor_id,
                timestamp=datetime.now(UTC),
                latency_ms=self.timeout_s * 1000,
                http_status=0,
                success=False,
                error='timeout',
            )
        except Exception as exc:
            return ProbeResult(
                vendor_id=self.vendor_id,
                timestamp=datetime.now(UTC),
                latency_ms=0.0,
                http_status=0,
                success=False,
                error=str(exc),
            )

class SLATracker:
    def __init__(self, availability_sla: float = 0.999,
                 latency_p99_ms: float = 500.0):
        self.availability_sla = availability_sla
        self.latency_p99_ms = latency_p99_ms
        self._results: list[ProbeResult] = []

    def record(self, result: ProbeResult) -> None:
        self._results.append(result)

    def hourly_summary(self) -> dict:
        if not self._results:
            return {}
        success_count = sum(1 for r in self._results if r.success)
        availability = success_count / len(self._results)
        latencies = sorted(r.latency_ms for r in self._results if r.success)
        p99_idx = int(len(latencies) * 0.99) if latencies else 0
        p99 = latencies[p99_idx] if latencies else 0.0
        breach = (availability < self.availability_sla
                  or p99 > self.latency_p99_ms)
        return {
            'probe_count': len(self._results),
            'availability': round(availability, 5),
            'p99_latency_ms': round(p99, 1),
            'sla_breach': breach,
        }
